return [
  { json: { season: 2024 } },
  { json: { season: 2023 } },
  { json: { season: 2022 } },
  { json: { season: 2021 } }
];

function mapStatus(status) {
  if (!status) return "scheduled";

  const s = String(status).toLowerCase().trim();

  if (s === "scheduled" || s === "timed") return "scheduled";
  if (s === "finished") return "finished";
  if (s === "in_play" || s === "live") return "live";

  // Estos los llevamos a scheduled para no romper el check constraint
  if (
    s === "postponed" ||
    s === "suspended" ||
    s === "paused" ||
    s === "canceled" ||
    s === "cancelled" ||
    s === "awarded"
  ) {
    return "scheduled";
  }

  return "scheduled";
}

let allMatches = [];

for (const item of items) {
  if (item.json && Array.isArray(item.json.matches)) {
    allMatches.push(...item.json.matches);
  }
}

return allMatches.map(m => ({
  json: {
    external_id: m.id || null,
    utc_date: m.utcDate || null,
    status: mapStatus(m.status),
    raw_status: m.status || null,

    matchday: m.matchday || null,
    stage: m.stage || null,

    home_team_external: m.homeTeam?.id || null,
    home_team_name: m.homeTeam?.name || null,

    away_team_external: m.awayTeam?.id || null,
    away_team_name: m.awayTeam?.name || null,

    competition_external: m.competition?.id || null,
    competition_name: m.competition?.name || null,
    competition_code: m.competition?.code || null,

    season_external: m.season?.id || null,
    season_start: m.season?.startDate || null,
    season_end: m.season?.endDate || null,
    season:
      m.season?.startDate && m.season?.endDate
        ? `${m.season.startDate.slice(0, 4)}/${m.season.endDate.slice(2, 4)}`
        : null,

    country_code: m.area?.code || null,
    country_name: m.area?.name || null,

    home_score: m.score?.fullTime?.home ?? null,
    away_score: m.score?.fullTime?.away ?? null
  }
}));

const mergedItems = items.map(i => i.json);

// Buscar el item que trae el array de equipos
const teamsContainer = mergedItems.find(i => Array.isArray(i.teams));
const teams = teamsContainer?.teams || [];

// Los demás items son partidos
const matches = mergedItems.filter(i => !Array.isArray(i.teams));

const teamsByExternalId = new Map();

for (const team of teams) {
  const externalId = Number(team.external_id);
  if (!Number.isNaN(externalId)) {
    teamsByExternalId.set(externalId, team);
  }
}

return matches.map(match => {
  const homeExternal = Number(match.home_team_external);
  const awayExternal = Number(match.away_team_external);

  const homeTeam = teamsByExternalId.get(homeExternal) || null;
  const awayTeam = teamsByExternalId.get(awayExternal) || null;

  return {
    json: {
      ...match,
      home_team_id: homeTeam ? homeTeam.id : null,
      away_team_id: awayTeam ? awayTeam.id : null,
    }
  };
});

const batchSize = 50;
const all = items.map(i => i.json);
const result = [];

for (let i = 0; i < all.length; i += batchSize) {
  result.push({
    json: {
      rows: all.slice(i, i + batchSize)
    }
  });
}

return result;
